import{_ as a,m as r,k as t,ah as n}from"./chunks/framework.DYy1ogWd.js";const p=JSON.parse('{"title":"Release notes","description":"","frontmatter":{},"headers":[],"relativePath":"release-notes.md","filePath":"src/en/release-notes.md"}'),i={name:"release-notes.md"};function o(s,e,l,d,h,u){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="release-notes" tabindex="-1">Release notes <a class="header-anchor" href="#release-notes" aria-label="Permalink to &quot;Release notes&quot;">​</a></h1><h2 id="latest-releases-v0-8-x-—-april-2026" tabindex="-1">Latest Releases (v0.8.x) — April 2026 <a class="header-anchor" href="#latest-releases-v0-8-x-—-april-2026" aria-label="Permalink to &quot;Latest Releases (v0.8.x) — April 2026&quot;">​</a></h2><p><strong>Navigation menu</strong> management has been significantly improved: new menu item creation form, support for various item types, and bug fixes related to their configuration. Newly created pages now automatically appear at the bottom of the list. Several libraries have been updated (Vue, Vue Router, CKEditor text editor, etc.).</p><h2 id="v0-8-2-—-april-2026" tabindex="-1">v0.8.2 — April 2026 <a class="header-anchor" href="#v0-8-2-—-april-2026" aria-label="Permalink to &quot;v0.8.2 — April 2026&quot;">​</a></h2><p>Added the ability to configure <strong>available languages</strong> directly within the application settings. Dependency updates.</p><h2 id="v0-8-1-—-april-2026" tabindex="-1">v0.8.1 — April 2026 <a class="header-anchor" href="#v0-8-1-—-april-2026" aria-label="Permalink to &quot;v0.8.1 — April 2026&quot;">​</a></h2><p>Fixes for the <strong>plugin system</strong>: dashboard and settings modules are no longer mandatory for plugins, and each plugin now indicates whether it includes a UI.</p><h2 id="v0-8-0-—-march-2026" tabindex="-1">v0.8.0 — March 2026 <a class="header-anchor" href="#v0-8-0-—-march-2026" aria-label="Permalink to &quot;v0.8.0 — March 2026&quot;">​</a></h2><p>New <strong>plugin management</strong> page with improved activation/deactivation. Upgrade to Vite 7.</p><h2 id="v0-7-7-—-march-2026" tabindex="-1">v0.7.7 — March 2026 <a class="header-anchor" href="#v0-7-7-—-march-2026" aria-label="Permalink to &quot;v0.7.7 — March 2026&quot;">​</a></h2><p><strong>Content management</strong> improvements: page search filter in the sidebar, ability to reorder pages, and support for link titles in page sections.</p><h2 id="v0-7-5-—-march-2026" tabindex="-1">v0.7.5 — March 2026 <a class="header-anchor" href="#v0-7-5-—-march-2026" aria-label="Permalink to &quot;v0.7.5 — March 2026&quot;">​</a></h2><p>In development mode, access to raw data for content items is now available to facilitate debugging. Dependency updates.</p><h2 id="v0-7-4-—-february-2026" tabindex="-1">v0.7.4 — February 2026 <a class="header-anchor" href="#v0-7-4-—-february-2026" aria-label="Permalink to &quot;v0.7.4 — February 2026&quot;">​</a></h2><p><strong>Responsive UI</strong> improvements for all screen sizes. Fixed a bug regarding data structure settings. Major dependency updates (vue-i18n, CKEditor, etc.).</p><h2 id="v0-7-3-—-february-2026" tabindex="-1">v0.7.3 — February 2026 <a class="header-anchor" href="#v0-7-3-—-february-2026" aria-label="Permalink to &quot;v0.7.3 — February 2026&quot;">​</a></h2><p>Numerous improvements to the <strong>visual editor</strong>: better section field management and adaptation of the form generator.</p><h2 id="v0-7-2-—-february-2026" tabindex="-1">v0.7.2 — February 2026 <a class="header-anchor" href="#v0-7-2-—-february-2026" aria-label="Permalink to &quot;v0.7.2 — February 2026&quot;">​</a></h2><p>Improvements to the <strong>initial setup wizard</strong>: enhanced database creation and bug fixes. CKEditor and Vue updates.</p><h2 id="v0-7-1-—-february-2026" tabindex="-1">v0.7.1 — February 2026 <a class="header-anchor" href="#v0-7-1-—-february-2026" aria-label="Permalink to &quot;v0.7.1 — February 2026&quot;">​</a></h2><p>The <strong>icon picker</strong> in application settings can now be configured to return the icon name.</p><h2 id="v0-7-0-—-february-2026" tabindex="-1">v0.7.0 — February 2026 <a class="header-anchor" href="#v0-7-0-—-february-2026" aria-label="Permalink to &quot;v0.7.0 — February 2026&quot;">​</a></h2><p>Complete overhaul of the <strong>access and authentication system</strong>, featuring new API services and a cleaner architecture.</p><h2 id="v0-6-x-—-december-2025-–-january-2026" tabindex="-1">v0.6.x — December 2025 – January 2026 <a class="header-anchor" href="#v0-6-x-—-december-2025-–-january-2026" aria-label="Permalink to &quot;v0.6.x — December 2025 – January 2026&quot;">​</a></h2><p>Management of <strong>video metadata and visibility</strong>. Bug fixes for the visual editor.</p><h2 id="v0-6-0-—-december-2025" tabindex="-1">v0.6.0 — December 2025 <a class="header-anchor" href="#v0-6-0-—-december-2025" aria-label="Permalink to &quot;v0.6.0 — December 2025&quot;">​</a></h2><p>Launch of the <strong>visual editor</strong>: manage page sections directly from the interface with a dedicated sidebar.</p><h2 id="v0-5-0-rc-x-—-september–november-2025" tabindex="-1">v0.5.0-rc.x — September–November 2025 <a class="header-anchor" href="#v0-5-0-rc-x-—-september–november-2025" aria-label="Permalink to &quot;v0.5.0-rc.x — September–November 2025&quot;">​</a></h2><p>Gradual improvements to the visual editor: data copying between sections, drag-and-drop reordering, preview mode, and better content model management.</p><h2 id="v0-5-0-rc-1-—-september-2025" tabindex="-1">v0.5.0-rc.1 — September 2025 <a class="header-anchor" href="#v0-5-0-rc-1-—-september-2025" aria-label="Permalink to &quot;v0.5.0-rc.1 — September 2025&quot;">​</a></h2><p>Major update: main layout redesign, media library improvements, and CKEditor version upgrade.</p><h2 id="v0-0-17-—-august-2025" tabindex="-1">v0.0.17 — August 2025 <a class="header-anchor" href="#v0-0-17-—-august-2025" aria-label="Permalink to &quot;v0.0.17 — August 2025&quot;">​</a></h2><p>Performance optimizations: cached queries for articles, newsletters, and other data.</p><h2 id="v0-0-16-—-may-2025" tabindex="-1">v0.0.16 — May 2025 <a class="header-anchor" href="#v0-0-16-—-may-2025" aria-label="Permalink to &quot;v0.0.16 — May 2025&quot;">​</a></h2><p>Implementation of the <strong>plugin system</strong>.</p><h2 id="v0-0-14-—-april-2025" tabindex="-1">v0.0.14 — April 2025 <a class="header-anchor" href="#v0-0-14-—-april-2025" aria-label="Permalink to &quot;v0.0.14 — April 2025&quot;">​</a></h2><p>Integration of <strong>auto-translation APIs</strong> into multilingual fields. User import and export functionality.</p><h2 id="v0-0-13-—-march-2025" tabindex="-1">v0.0.13 — March 2025 <a class="header-anchor" href="#v0-0-13-—-march-2025" aria-label="Permalink to &quot;v0.0.13 — March 2025&quot;">​</a></h2><p>New field types in the form generator: date/time, time ranges, month, quarter, and week.</p><h2 id="v0-0-10-—-march-2025" tabindex="-1">v0.0.10 — March 2025 <a class="header-anchor" href="#v0-0-10-—-march-2025" aria-label="Permalink to &quot;v0.0.10 — March 2025&quot;">​</a></h2><p>Added list and multilingual list fields to the form generator.</p><h2 id="v0-0-8-—-february-2025" tabindex="-1">v0.0.8 — February 2025 <a class="header-anchor" href="#v0-0-8-—-february-2025" aria-label="Permalink to &quot;v0.0.8 — February 2025&quot;">​</a></h2><p>Mobile UI improvements (header and overall display). Configurable limit on multiple selections.</p><h2 id="v0-0-5-—-january-2025" tabindex="-1">v0.0.5 — January 2025 <a class="header-anchor" href="#v0-0-5-—-january-2025" aria-label="Permalink to &quot;v0.0.5 — January 2025&quot;">​</a></h2><p>Numerous fixes and new features: permalink management, media picker, auto-updating sections, section position display, performance, and pagination fixes.</p><h2 id="v0-0-2-—-january-2025" tabindex="-1">v0.0.2 — January 2025 <a class="header-anchor" href="#v0-0-2-—-january-2025" aria-label="Permalink to &quot;v0.0.2 — January 2025&quot;">​</a></h2><p>First public release: dashboard with visits map and video management.</p>',47)])])}const m=a(i,[["render",o]]);export{p as __pageData,m as default};
